questionvariables.text:
/* 1. Randomize side length s */
s: 6 + rand(10); 

/* 2. Calculate a realistic apothem a for a regular heptagon */
/* Formula: a = s / (2 * tan(180/7)) */
a_exact: float(s / (2 * tan(%pi/7)));
/* We provide a rounded version for the student to use, as in your screenshot */
a: decimalplaces(a_exact,2);

/* 3. Calculate Area using the requested formula: A = 7/2 * s * a */
ta1: s*a;
ta_1: decimalplaces(ta1,2);
ta_whole: (7/2) * s * a;
ta: decimalplaces(ta_whole,2);
